module linear_regression(
    input [7:0] x1,
    input [7:0] x2,
    output [15:0] y
);
    // Parameters for the linear regression
    parameter integer a = 2;
    parameter integer b = 3;
    parameter integer c = 5;

    // Calculate y = a*x1 + b*x2 + c
      wire _n01 = (a * x1) + (b * x2)[0] ^ c[0];
  wire _c01 = (a * x1) + (b * x2)[0] & c[0];
  wire _n02 = (a * x1) + (b * x2)[1] ^ c[1] ^ _c01;
  wire _c02 = ((a * x1) + (b * x2)[1] & c[1]) | ((a * x1) + (b * x2)[1] & _c01) | (c[1] & _c01);
  wire _n03 = (a * x1) + (b * x2)[2] ^ c[2] ^ _c02;
  wire _c03 = ((a * x1) + (b * x2)[2] & c[2]) | ((a * x1) + (b * x2)[2] & _c02) | (c[2] & _c02);
  wire _n04 = (a * x1) + (b * x2)[3] ^ c[3] ^ _c03;
  wire _c04 = ((a * x1) + (b * x2)[3] & c[3]) | ((a * x1) + (b * x2)[3] & _c03) | (c[3] & _c03);
  assign y = {_n01, _n02, _n03, _n04};

endmodule
